<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_STRICT_TERMINAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ghostty</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span>
